#!/bin/bash
set -e
echo "=== Setting up task ==="

# Record task start time
date +%s > /tmp/task_start_time.txt

# Include task utils
source /workspace/scripts/task_utils.sh

# Ensure application is running
ensure_services_running

# Wait for Drupal
wait_for_drupal 60

# 1. Ensure enough products exist for the cross-sell task (Need at least 5)
# If < 5, create dummy products so the task is visually verifiable
COUNT=$($DRUSH php:eval "echo \Drupal\commerce_product\Entity\Product::query()->count();" 2>/dev/null || echo "0")
if [ "$COUNT" -lt "5" ]; then
  echo "Creating dummy products for task..."
  $DRUSH php:eval '
    use Drupal\commerce_product\Entity\Product;
    use Drupal\commerce_product\Entity\ProductVariation;
    use Drupal\commerce_price\Price;

    $store = \Drupal\commerce_store\Entity\Store::load(1);
    if (!$store) {
       $store = \Drupal\commerce_store\Entity\Store::create([
         "type" => "online", "uid" => 1, "name" => "Default Store", "mail" => "admin@example.com", "default_currency" => "USD"
       ]);
       $store->save();
    }

    for ($i=1; $i<=5; $i++) {
      // Check if sku exists
      $sku = "TEST-" . $i;
      $exists = \Drupal\commerce_product\Entity\ProductVariation::loadBySku($sku);
      if (!$exists) {
          $variation = ProductVariation::create(["type" => "default", "sku" => $sku, "price" => new Price("10.00", "USD")]);
          $variation->save();
          $product = Product::create(["type" => "default", "title" => "Test Product " . $i, "stores" => [$store], "variations" => [$variation]]);
          $product->save();
          echo "Created Test Product " . $i . "\n";
      }
    }
  ' 2>&1
fi

# 2. Launch Firefox and login
if ! pgrep -f "firefox" > /dev/null; then
    echo "Starting Firefox..."
    su - ga -c "DISPLAY=:1 firefox &"
    sleep 5
fi

ensure_drupal_shown

# Maximize window
WID=$(get_firefox_window_id)
if [ -n "$WID" ]; then
    DISPLAY=:1 wmctrl -ir "$WID" -b add,maximized_vert,maximized_horz
fi

# Navigate to Views UI to help them start (Context)
navigate_firefox_to "http://localhost/admin/structure/views"

# Take screenshot of initial state
take_screenshot "/tmp/task_initial_state.png"

echo "=== Task setup complete ==="
